<!DOCTYPE html>
<html lang="ko">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>지뢰찾기</title>
<style>
  * { margin: 0; padding: 0; box-sizing: border-box; }
  body {
    background: #c0c0c0;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    min-height: 100vh;
    font-family: 'Segoe UI', sans-serif;
  }
  h1 { margin-bottom: 10px; font-size: 24px; color: #333; }
  .info-bar {
    display: flex;
    gap: 20px;
    align-items: center;
    margin-bottom: 10px;
    background: #999;
    padding: 8px 20px;
    border: 2px inset #fff;
    font-size: 20px;
    font-weight: bold;
    color: red;
    font-family: 'Courier New', monospace;
  }
  .info-bar span { background: #000; padding: 4px 10px; min-width: 50px; text-align: center; }
  #face-btn {
    font-size: 26px;
    cursor: pointer;
    background: #c0c0c0;
    border: 2px outset #fff;
    padding: 2px 6px;
    line-height: 1;
  }
  #face-btn:active { border-style: inset; }
  .board {
    display: inline-grid;
    gap: 0;
    border: 3px inset #fff;
    background: #c0c0c0;
  }
  .cell {
    width: 36px;
    height: 36px;
    border: 2px outset #fff;
    background: #c0c0c0;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 18px;
    font-weight: bold;
    cursor: pointer;
    user-select: none;
  }
  .cell.revealed {
    border: 1px solid #999;
    background: #d0d0d0;
    cursor: default;
  }
  .cell.mine-exploded {
    background: red;
  }
  .cell.flagged::after {
    content: '\1F6A9';
    font-size: 18px;
  }
  .n1 { color: blue; }
  .n2 { color: green; }
  .n3 { color: red; }
  .n4 { color: darkblue; }
  .n5 { color: darkred; }
  .n6 { color: teal; }
  .n7 { color: black; }
  .n8 { color: gray; }
  .help {
    margin-top: 14px;
    font-size: 15px;
    color: #555;
    text-align: center;
    line-height: 1.8;
  }
  .difficulty {
    margin-bottom: 12px;
    display: flex;
    gap: 8px;
  }
  .difficulty button {
    padding: 6px 16px;
    font-size: 15px;
    cursor: pointer;
    background: #c0c0c0;
    border: 2px outset #fff;
    font-weight: bold;
  }
  .difficulty button:active, .difficulty button.active {
    border-style: inset;
    background: #a0a0a0;
  }
</style>
</head>
<body>

<h1>지뢰찾기 💣</h1>

<div class="difficulty">
  <button onclick="init(9,9,10)" id="d-easy">쉬움</button>
  <button onclick="init(12,12,25)" id="d-medium">보통</button>
  <button onclick="init(16,16,50)" id="d-hard">어려움</button>
</div>

<div class="info-bar">
  <span id="mine-count">10</span>
  <button id="face-btn" onclick="restartGame()">😀</button>
  <span id="timer">000</span>
</div>

<div class="board" id="board" oncontextmenu="return false"></div>

<div class="help">
  <b>왼쪽 클릭</b> = 칸 열기 &nbsp;|&nbsp; <b>오른쪽 클릭</b> = 깃발 꽂기 (지뢰 표시)<br>
  숫자 = 주변 8칸에 있는 지뢰 개수<br>
  지뢰를 모두 피하고 빈 칸을 다 열면 승리!
</div>

<script>
let rows, cols, totalMines;
let board, revealed, flagged, mines;
let gameOver, gameWon, firstClick;
let timerInterval, seconds;
let flagCount;

function init(r, c, m) {
  rows = r; cols = c; totalMines = m;
  document.querySelectorAll('.difficulty button').forEach(b => b.classList.remove('active'));
  if (r === 9) document.getElementById('d-easy').classList.add('active');
  else if (r === 12) document.getElementById('d-medium').classList.add('active');
  else document.getElementById('d-hard').classList.add('active');
  restartGame();
}

function restartGame() {
  gameOver = false;
  gameWon = false;
  firstClick = true;
  flagCount = 0;
  seconds = 0;
  clearInterval(timerInterval);
  document.getElementById('timer').textContent = '000';
  document.getElementById('mine-count').textContent = String(totalMines).padStart(3, '0');
  document.getElementById('face-btn').textContent = '😀';

  board = Array.from({length: rows}, () => Array(cols).fill(0));
  revealed = Array.from({length: rows}, () => Array(cols).fill(false));
  flagged = Array.from({length: rows}, () => Array(cols).fill(false));
  mines = Array.from({length: rows}, () => Array(cols).fill(false));

  renderBoard();
}

function placeMines(safeR, safeC) {
  let placed = 0;
  while (placed < totalMines) {
    let r = Math.floor(Math.random() * rows);
    let c = Math.floor(Math.random() * cols);
    if (mines[r][c]) continue;
    if (Math.abs(r - safeR) <= 1 && Math.abs(c - safeC) <= 1) continue;
    mines[r][c] = true;
    placed++;
  }
  for (let r = 0; r < rows; r++) {
    for (let c = 0; c < cols; c++) {
      if (mines[r][c]) { board[r][c] = -1; continue; }
      let count = 0;
      for (let dr = -1; dr <= 1; dr++)
        for (let dc = -1; dc <= 1; dc++) {
          let nr = r+dr, nc = c+dc;
          if (nr>=0 && nr<rows && nc>=0 && nc<cols && mines[nr][nc]) count++;
        }
      board[r][c] = count;
    }
  }
}

function renderBoard() {
  const el = document.getElementById('board');
  el.style.gridTemplateColumns = `repeat(${cols}, 36px)`;
  el.innerHTML = '';
  for (let r = 0; r < rows; r++) {
    for (let c = 0; c < cols; c++) {
      const cell = document.createElement('div');
      cell.className = 'cell';
      cell.dataset.r = r;
      cell.dataset.c = c;
      cell.addEventListener('click', () => handleClick(r, c));
      cell.addEventListener('contextmenu', (e) => { e.preventDefault(); handleFlag(r, c); });
      el.appendChild(cell);
    }
  }
}

function getCell(r, c) {
  return document.querySelector(`.cell[data-r="${r}"][data-c="${c}"]`);
}

function handleClick(r, c) {
  if (gameOver || gameWon || flagged[r][c] || revealed[r][c]) return;
  if (firstClick) {
    firstClick = false;
    placeMines(r, c);
    timerInterval = setInterval(() => {
      seconds++;
      document.getElementById('timer').textContent = String(seconds).padStart(3, '0');
    }, 1000);
  }
  if (mines[r][c]) {
    gameOver = true;
    clearInterval(timerInterval);
    document.getElementById('face-btn').textContent = '😵';
    revealAll(r, c);
    return;
  }
  reveal(r, c);
  checkWin();
}

function reveal(r, c) {
  if (r<0||r>=rows||c<0||c>=cols) return;
  if (revealed[r][c] || flagged[r][c]) return;
  revealed[r][c] = true;
  const cell = getCell(r, c);
  cell.classList.add('revealed');
  if (board[r][c] > 0) {
    cell.textContent = board[r][c];
    cell.classList.add('n' + board[r][c]);
  } else if (board[r][c] === 0) {
    for (let dr = -1; dr <= 1; dr++)
      for (let dc = -1; dc <= 1; dc++)
        reveal(r+dr, c+dc);
  }
}

function handleFlag(r, c) {
  if (gameOver || gameWon || revealed[r][c]) return;
  const cell = getCell(r, c);
  flagged[r][c] = !flagged[r][c];
  if (flagged[r][c]) {
    cell.classList.add('flagged');
    flagCount++;
  } else {
    cell.classList.remove('flagged');
    flagCount--;
  }
  document.getElementById('mine-count').textContent = String(totalMines - flagCount).padStart(3, '0');
}

function revealAll(clickR, clickC) {
  for (let r = 0; r < rows; r++)
    for (let c = 0; c < cols; c++) {
      const cell = getCell(r, c);
      if (mines[r][c]) {
        cell.classList.add('revealed');
        cell.textContent = '💣';
        if (r === clickR && c === clickC) cell.classList.add('mine-exploded');
      }
    }
}

function checkWin() {
  let unrevealed = 0;
  for (let r = 0; r < rows; r++)
    for (let c = 0; c < cols; c++)
      if (!revealed[r][c]) unrevealed++;
  if (unrevealed === totalMines) {
    gameWon = true;
    clearInterval(timerInterval);
    document.getElementById('face-btn').textContent = '😎';
    for (let r = 0; r < rows; r++)
      for (let c = 0; c < cols; c++)
        if (mines[r][c]) {
          flagged[r][c] = true;
          getCell(r, c).classList.add('flagged');
        }
    document.getElementById('mine-count').textContent = '000';
    setTimeout(() => alert('축하합니다! 클리어! 🎉\n시간: ' + seconds + '초'), 200);
  }
}

init(9, 9, 10);
</script>

</body>
</html>

